import { describe, expect, it } from 'vitest';

import {
  AcousticSceneMaster,
  adist,
  admitScene,
  confident,
  distancesToPrototypes,
  fpDistance,
  inVehicle,
  indoor,
  outdoor,
  prototypes,
  sep,
  signatureAmbiguous,
  signatureIndoor,
  tol,
  tolAmbig,
} from '../src/acoustic-scene-classification';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(32, 30)).toBe(2);
    expect(adist(30, 32)).toBe(2);
    expect(adist(6, 25)).toBe(19);
    expect(adist(25, 6)).toBe(19);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('fpDistance (mirrors fpDistance_self + hand-computed distances)', () => {
  it('is zero from a signature to itself', () => {
    expect(fpDistance(signatureIndoor, signatureIndoor)).toBe(0);
    expect(fpDistance(signatureAmbiguous, signatureAmbiguous)).toBe(0);
  });

  it('matches the Lean hand-computed indoor-signature distances', () => {
    // |32-30|+|6-5|+|7-8| = 2+1+1 = 4
    expect(fpDistance(signatureIndoor, indoor.signature)).toBe(4);
    // |32-5|+|6-25|+|7-3| = 27+19+4 = 50
    expect(fpDistance(signatureIndoor, outdoor.signature)).toBe(50);
    // |32-10|+|6-15|+|7-40| = 22+9+33 = 64
    expect(fpDistance(signatureIndoor, inVehicle.signature)).toBe(64);
  });

  it('matches the Lean hand-computed ambiguous-signature distances', () => {
    // |18-30|+|15-5|+|5-8| = 12+10+3 = 25
    expect(fpDistance(signatureAmbiguous, indoor.signature)).toBe(25);
    // |18-5|+|15-25|+|5-3| = 13+10+2 = 25 (equal -> the ambiguity)
    expect(fpDistance(signatureAmbiguous, outdoor.signature)).toBe(25);
    // |18-10|+|15-15|+|5-40| = 8+0+35 = 43
    expect(fpDistance(signatureAmbiguous, inVehicle.signature)).toBe(43);
  });
});

describe('distancesToPrototypes', () => {
  it('returns distances to every prototype in order', () => {
    expect(distancesToPrototypes(signatureIndoor, prototypes)).toEqual([
      4, 50, 64,
    ]);
    expect(distancesToPrototypes(signatureAmbiguous, prototypes)).toEqual([
      25, 25, 43,
    ]);
  });
});

describe('confident (mirrors confidentB)', () => {
  it('passes when every other distance exceeds claimed + sep', () => {
    // claimed 4, others [50, 64], need each > 4+8 = 12
    expect(confident(sep, 4, [50, 64])).toBe(true);
  });

  it('fails when a second prototype sits within the margin (ambiguity)', () => {
    // claimed 25, others [25, 43], need each > 25+8 = 33; 25 fails
    expect(confident(sep, 25, [25, 43])).toBe(false);
  });

  it('is vacuously true with no other prototypes', () => {
    expect(confident(sep, 100, [])).toBe(true);
  });

  it('uses a strict margin (equality at the boundary fails)', () => {
    // claimed 0, sep 8: other = 8 is NOT > 8, so it fails
    expect(confident(8, 0, [8])).toBe(false);
    expect(confident(8, 0, [9])).toBe(true);
  });
});

describe('promotion check: admitScene', () => {
  it('admits the clearly-indoor signature as indoor (match + confident margin)', () => {
    const a = admitScene(signatureIndoor, prototypes, 0, { tol, sep });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.label).toBe('indoor');
    expect(a.claimedDistance).toBe(4);
    expect(a.otherDistances).toEqual([50, 64]);
    expect(a.matched).toBe(true);
    expect(a.confident).toBe(true);
  });

  it('withholds the indoor signature claimed as outdoor on the match gate', () => {
    // mirrors indoor_not_outdoor: claimed distance 50 > tol 10
    const a = admitScene(signatureIndoor, prototypes, 1, { tol, sep });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('match_fail');
    expect(a.label).toBe('outdoor');
    expect(a.claimedDistance).toBe(50);
    expect(a.matched).toBe(false);
    expect(a.summary).toContain('match fail');
  });

  it('withholds the ambiguous signature on the margin gate, not the match gate', () => {
    // mirrors ambiguous_rejected under the raised tolerance
    const a = admitScene(signatureAmbiguous, prototypes, 0, {
      tol: tolAmbig,
      sep,
    });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('ambiguous_margin');
    expect(a.matched).toBe(true); // 25 <= 30, match PASSES
    expect(a.confident).toBe(false); // outdoor at 25 within margin
    expect(a.claimedDistance).toBe(25);
    expect(a.otherDistances).toEqual([25, 43]);
    expect(a.summary).toContain('ambiguous');
  });

  it('reports observation_only with an empty prototype library', () => {
    const a = admitScene(signatureIndoor, [], 0, { tol, sep });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('no_prototypes');
  });
});

describe('AcousticSceneMaster (mirrors acoustic_scene_master)', () => {
  it('every boundary witness holds', () => {
    expect(AcousticSceneMaster.fpDistanceSelfZero).toBe(true);
    expect(AcousticSceneMaster.dIndoorIndoor).toBe(true);
    expect(AcousticSceneMaster.dIndoorOutdoor).toBe(true);
    expect(AcousticSceneMaster.dIndoorInVehicle).toBe(true);
    expect(AcousticSceneMaster.dAmbigIndoor).toBe(true);
    expect(AcousticSceneMaster.dAmbigOutdoor).toBe(true);
    expect(AcousticSceneMaster.dAmbigInVehicle).toBe(true);
    expect(AcousticSceneMaster.indoorAdmitted).toBe(true);
    expect(AcousticSceneMaster.indoorNotOutdoor).toBe(true);
    expect(AcousticSceneMaster.ambiguousMarginFails).toBe(true);
    expect(AcousticSceneMaster.ambiguousMatchPasses).toBe(true);
    expect(AcousticSceneMaster.ambiguousRejected).toBe(true);
    expect(AcousticSceneMaster.sceneDistinguishable).toBe(true);
  });
});
